"use client"

import { useEffect, useState } from "react"

/**
 * Isometric wireframe drawing of the heating-oil tank, generated by the
 * fuelmeter-figma plugin and traced from the Paper design ("Zealous
 * thistle / Tank Drawing"). The line art is static; the fluid body and
 * surface ellipse are computed from the fill percentage.
 */

// Tank interior geometry in viewBox coordinates (see WIREFRAME_D below).
const VIEW_W = 228.19
const VIEW_H = 352.12
const CX = 114.098 // tank axis
const RX = 92.243 // fluid ellipse radii (slightly inside the shell rims)
const RY = 53.256
const BOTTOM_CY = 273.029 // fluid surface center at 0%
const TOP_CY = 78 // fluid surface center at 100%, just under the top rim

function fluidSurfaceCy(pct: number) {
  const t = Math.min(100, Math.max(0, pct)) / 100
  return BOTTOM_CY - t * (BOTTOM_CY - TOP_CY)
}

function fluidBodyPath(cyS: number) {
  const left = CX - RX
  const right = CX + RX
  return [
    `M ${left} ${cyS}`,
    `L ${left} ${BOTTOM_CY}`,
    `A ${RX} ${RY} 0 0 0 ${right} ${BOTTOM_CY}`, // bottom cap, bulging down
    `L ${right} ${cyS}`,
    `A ${RX} ${RY} 0 0 1 ${left} ${cyS}`, // front half of the surface
    "Z",
  ].join(" ")
}

/** Ease the fluid up from empty on first render. */
function useAnimatedPercent(target: number) {
  const [value, setValue] = useState(0)

  useEffect(() => {
    if (
      typeof window !== "undefined" &&
      window.matchMedia("(prefers-reduced-motion: reduce)").matches
    ) {
      setValue(target)
      return
    }
    let raf = 0
    const duration = 900
    const from = 0
    const start = performance.now()
    const tick = (now: number) => {
      const t = Math.min(1, (now - start) / duration)
      const eased = 1 - Math.pow(1 - t, 3)
      setValue(from + (target - from) * eased)
      if (t < 1) raf = requestAnimationFrame(tick)
    }
    raf = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(raf)
  }, [target])

  return value
}

interface TankIllustrationProps {
  /** Fill level 0–100 */
  percent: number
  className?: string
}

export function TankIllustration({ percent, className }: TankIllustrationProps) {
  const displayPct = useAnimatedPercent(percent)
  const cyS = fluidSurfaceCy(displayPct)

  return (
    <svg
      viewBox={`0 0 ${VIEW_W} ${VIEW_H}`}
      className={className}
      role="img"
      aria-label={`Heating oil tank, ${Math.round(percent)}% full`}
    >
      {/* fluid body */}
      {displayPct > 0.5 && (
        <path d={fluidBodyPath(cyS)} fill="var(--shade)" />
      )}
      {/* fluid surface with a subtle wave shimmer */}
      {displayPct > 0.5 && (
        <g
          className="tank-wave"
          style={{ transformOrigin: `${CX}px ${cyS}px` }}
        >
          <ellipse cx={CX} cy={cyS} rx={RX} ry={RY} fill="var(--fluid)" />
        </g>
      )}
      {/* wireframe line art */}
      <g transform="translate(15.763 15.763)">
        <path
          d={WIREFRAME_D}
          vectorEffect="non-scaling-stroke"
          fill="none"
          stroke="var(--ink)"
          strokeWidth="0.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </g>
    </svg>
  )
}

